/**
 * @summary Submit a survey response
 */
export const getSubmitResponseUrl = (responseId: string) => {
  return `/api/responses/${responseId}/submit`;
};

export const submitResponse = async (
  responseId: string,
  options?: RequestInit,
): Promise<SuccessResponse> => {
  return customFetch<SuccessResponse>(getSubmitResponseUrl(responseId), {
    ...options,
    method: "POST",
  });
};

export const getSubmitResponseMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof submitResponse>>,
    TError,
    { responseId: string },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof submitResponse>>,
  TError,
  { responseId: string },
  TContext
> => {
  const mutationKey = ["submitResponse"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof submitResponse>>,
    { responseId: string }
  > = (props) => {
    const { responseId } = props ?? {};

    return submitResponse(responseId, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type SubmitResponseMutationResult = NonNullable<
  Awaited<ReturnType<typeof submitResponse>>
>;

export type SubmitResponseMutationError = ErrorType<unknown>;

/**
 * @summary Submit a survey response
 */
export const useSubmitResponse = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof submitResponse>>,
    TError,
    { responseId: string },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof submitResponse>>,
  TError,
  { responseId: string },
  TContext
> => {
  return useMutation(getSubmitResponseMutationOptions(options));
};

/**
 * @summary Get overall dashboard stats
 */
export const getGetDashboardOverviewUrl = () => {
  return `/api/dashboard/overview`;
};

export const getDashboardOverview = async (
  options?: RequestInit,
): Promise<DashboardOverview> => {
  return customFetch<DashboardOverview>(getGetDashboardOverviewUrl(), {
    ...options,
    method: "GET",
  });
};

export const getGetDashboardOverviewQueryKey = () => {
  return [`/api/dashboard/overview`] as const;
};

export const getGetDashboardOverviewQueryOptions = <
  TData = Awaited<ReturnType<typeof getDashboardOverview>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getDashboardOverview>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetDashboardOverviewQueryKey();

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getDashboardOverview>>
  > = ({ signal }) => getDashboardOverview({ signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getDashboardOverview>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetDashboardOverviewQueryResult = NonNullable<
  Awaited<ReturnType<typeof getDashboardOverview>>
>;
export type GetDashboardOverviewQueryError = ErrorType<unknown>;

/**
 * @summary Get overall dashboard stats
 */

export function useGetDashboardOverview<
  TData = Awaited<ReturnType<typeof getDashboardOverview>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getDashboardOverview>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetDashboardOverviewQueryOptions(options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

/**
 * @summary Get detailed analytics for a specific survey
 */
export const getGetSurveyDashboardUrl = (surveyId: string) => {
  return `/api/dashboard/surveys/${surveyId}`;
};

export const getSurveyDashboard = async (
  surveyId: string,
  options?: RequestInit,
): Promise<SurveyDashboard> => {
  return customFetch<SurveyDashboard>(getGetSurveyDashboardUrl(surveyId), {
    ...options,
    method: "GET",
  });
};

export const getGetSurveyDashboardQueryKey = (surveyId: string) => {
  return [`/api/dashboard/surveys/${surveyId}`] as const;
};

export const getGetSurveyDashboardQueryOptions = <
  TData = Awaited<ReturnType<typeof getSurveyDashboard>>,
  TError = ErrorType<unknown>,
>(
  surveyId: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getSurveyDashboard>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetSurveyDashboardQueryKey(surveyId);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getSurveyDashboard>>
  > = ({ signal }) =>
    getSurveyDashboard(surveyId, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!surveyId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getSurveyDashboard>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetSurveyDashboardQueryResult = NonNullable<
  Awaited<ReturnType<typeof getSurveyDashboard>>
>;
export type GetSurveyDashboardQueryError = ErrorType<unknown>;

/**
 * @summary Get detailed analytics for a specific survey
 */

export function useGetSurveyDashboard<
  TData = Awaited<ReturnType<typeof getSurveyDashboard>>,
  TError = ErrorType<unknown>,
>(
  surveyId: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getSurveyDashboard>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetSurveyDashboardQueryOptions(surveyId, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
